def dispatch(queue_lengths, queue_ages_ms, num_workers):
    min_index = 0
    min_value = float('inf')
    for w in range(num_workers):
        eff = queue_lengths[w] - queue_ages_ms[w] / 1.0
        if eff < 0:
            eff = 0
        # Add small random noise to break ties uniformly
        eff += random.random() * 0.01
        if eff < min_value:
            min_value = eff
            min_index = w
    return min_index

