def dispatch(queue_lengths, queue_ages_ms, num_workers):
    adjusted = []
    for w in range(num_workers):
        adj_len = max(queue_lengths[w] - queue_ages_ms[w], 0)
        adjusted.append((adj_len, w))
    min_adj = min(adjusted, key=lambda x: x[0])
    candidates = [w for (len_, w) in adjusted if len_ == min_adj[0]]
    return random.choice(candidates)
